// Normalizar y validar datos del webhook
const body = $input.first().json.body || $input.first().json;

const searchId = body.search_id;
const userId = body.user_id;
const profile = body.profile;
const criteria = body.criteria || {};

if (!searchId || !userId || !profile) {
  throw new Error('Datos incompletos: se requiere search_id, user_id y profile');
}

// Normalizar perfil
const normalizedProfile = {
  user_id: userId,
  city: (profile.city || '').toLowerCase().trim(),
  available_to_relocate: Boolean(profile.available_to_relocate),
  relocation_cities: Array.isArray(profile.relocation_cities) ? profile.relocation_cities : [],
  work_modality: Array.isArray(profile.work_modality) ? profile.work_modality : ['presencial'],
  immediate_availability: Boolean(profile.immediate_availability !== false),
  desired_salary_min: parseInt(profile.desired_salary_min) || null,
  desired_salary_max: parseInt(profile.desired_salary_max) || null,
  education_level: profile.education_level || null,
  years_experience: parseInt(profile.years_experience) || 0,
  experience_sectors: Array.isArray(profile.experience_sectors) ? profile.experience_sectors : [],
  technical_skills: Array.isArray(profile.technical_skills) ? profile.technical_skills : [],
  soft_skills: Array.isArray(profile.soft_skills) ? profile.soft_skills : [],
  languages: Array.isArray(profile.languages) ? profile.languages : [],
  bio: profile.bio || ''
};

console.log(`[NORMALIZE] search_id=${searchId} user_id=${userId} skills=${normalizedProfile.technical_skills.length}`);

return [{
  json: {
    search_id: searchId,
    user_id: userId,
    profile: normalizedProfile,
    criteria: {
      city: criteria.city || profile.city,
      work_modality: criteria.work_modality || profile.work_modality,
      min_salary: criteria.min_salary || profile.desired_salary_min,
      max_salary: criteria.max_salary || profile.desired_salary_max,
      keywords: criteria.keywords || '',
      categories: criteria.categories || []
    },
    timestamp: new Date().toISOString()
  }
}];

// Agrupar todas las vacantes en un solo objeto para enviar al scoring
const allItems = $input.all();
const normalizeNode = $('🔧 Normalizar Datos').first().json;

if (!allItems || allItems.length === 0) {
  console.log('[AGGREGATE] No se encontraron vacantes');
  return [{
    json: {
      search_id: normalizeNode.search_id,
      user_id: normalizeNode.user_id,
      profile: normalizeNode.profile,
      vacancies: [],
      jobs_found: 0
    }
  }];
}

const vacancies = allItems.map(item => ({
  id: item.json.id,
  title: item.json.title,
  company_name: item.json.company_name,
  city: item.json.city,
  work_modality: item.json.work_modality,
  contract_type: item.json.contract_type,
  required_education: item.json.required_education,
  required_experience_years: item.json.required_experience_years || 0,
  required_skills: typeof item.json.required_skills === 'string' 
    ? JSON.parse(item.json.required_skills) 
    : (item.json.required_skills || []),
  preferred_skills: typeof item.json.preferred_skills === 'string' 
    ? JSON.parse(item.json.preferred_skills) 
    : (item.json.preferred_skills || []),
  salary_min: item.json.salary_min,
  salary_max: item.json.salary_max,
  description: item.json.description,
  category: item.json.category
}));

console.log(`[AGGREGATE] ${vacancies.length} vacantes listas para scoring`);

return [{
  json: {
    search_id: normalizeNode.search_id,
    user_id: normalizeNode.user_id,
    profile: normalizeNode.profile,
    vacancies: vacancies,
    jobs_found: vacancies.length
  }
}];

