// Preparar matches para insertar en PostgreSQL
const scoringResponse = $input.first().json;
const aggregateData = $('📦 Agregar Vacantes').first().json;

const results = scoringResponse.results || [];

console.log(`[SAVE] Guardando ${results.length} matches para search_id=${aggregateData.search_id}`);

const matchesForDB = results.map(r => ({
  search_id: aggregateData.search_id,
  user_id: aggregateData.user_id,
  job_id: r.job_id,
  total_score: r.total_score,
  skills_score: r.breakdown.skills_score,
  experience_score: r.breakdown.experience_score,
  location_score: r.breakdown.location_score,
  salary_score: r.breakdown.salary_score,
  education_score: r.breakdown.education_score,
  modality_score: r.breakdown.modality_score,
  semantic_score: r.breakdown.semantic_score,
  score_explanation: JSON.stringify(r.explanation),
  matched_skills: r.matched_skills,
  missing_skills: r.missing_skills,
  rank_position: r.rank_position,
  recommendation: r.recommendation
}));

return matchesForDB.map(m => ({ json: m }));

// Simular envío de email de notificación
const userId = $('📦 Agregar Vacantes').first().json.user_id;
const searchId = $('📦 Agregar Vacantes').first().json.search_id;
const matchCount = $('🧠 Microservicio Scoring').first().json.results?.length || 0;

console.log(`[EMAIL] Simulando email para user=${userId}`);
console.log(`[EMAIL] Subject: ¡${matchCount} nuevas vacantes compatibles para ti!`);
console.log(`[EMAIL] Body: Hemos encontrado ${matchCount} vacantes que coinciden con tu perfil.`);
console.log(`[EMAIL] URL: http://localhost:3001/matches?search=${searchId}`);

// En producción: usar SendGrid, AWS SES, etc.
// const emailResult = await sendEmail({ to: userEmail, ... });

return [{
  json: {
    email_sent: true,
    simulated: true,
    user_id: userId,
    match_count: matchCount,
    timestamp: new Date().toISOString()
  }
}];
